// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import java.util.ArrayList;
import java.util.List;
import java.util.Locale;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

import org.eclipse.rdf4j.common.annotation.Experimental;
import org.eclipse.rdf4j.query.algebra.QueryModelNode;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * Planner telemetry hook. The recording implementation stores a bounded in-memory trace for diagnostics.
 */
@Experimental
public interface CascadesTelemetry {
	CascadesTelemetry NO_OP = new CascadesTelemetry() {
	};

	default void estimateDecision(int memoGroupId, String ruleId, double baseEstimateRows, double adjustedEstimateRows,
			QErrorInterval interval, PhysicalProperties physicalGoal) {
	}

	default void ruleFired(int memoGroupId, String ruleId, RuleProof proof) {
	}

	default void alternativeConsidered(int memoGroupId, String ruleId, RuleKind kind,
			PhysicalProperties deliveredProperties, CostVector localCost, String metadata, QueryModelNode plan) {
	}

	default void alternativeCosted(int memoGroupId, String ruleId, PhysicalProperties requiredProperties,
			PhysicalProperties deliveredProperties, CostVector cost, QueryModelNode plan) {
	}

	default void alternativeAccepted(int memoGroupId, String ruleId, CostVector cost, QueryModelNode plan) {
	}

	default void winnerChosen(WinnerKey key, Winner winner) {
	}

	default void alternativeRejected(int memoGroupId, String ruleId, String reason, CostVector cost) {
	}

	default void alternativeDiscarded(int memoGroupId, String ruleId, String reason, CostVector cost,
			QueryModelNode plan) {
		alternativeRejected(memoGroupId, ruleId, reason, cost);
	}

	default void executionActual(QueryModelNode node, long rows, long work) {
	}

	final class Recording implements CascadesTelemetry {
		private static final int DEFAULT_LIMIT = 512;
		private static final int PLAN_TEXT_LIMIT = 600;
		private static final Logger logger = LoggerFactory.getLogger(CascadesTelemetry.class);
		private final int limit;
		private final List<String> trace = new ArrayList<>();
		private final Map<Integer, String> chosenWinnerByGroup = new ConcurrentHashMap<>();

		public Recording() {
			this(DEFAULT_LIMIT);
		}

		public Recording(int limit) {
			this.limit = Math.max(1, limit);
		}

		@Override
		public synchronized void estimateDecision(int memoGroupId, String ruleId, double baseEstimateRows,
				double adjustedEstimateRows, QErrorInterval interval, PhysicalProperties physicalGoal) {
			append("estimate group=" + memoGroupId
					+ " rule=" + ruleId
					+ " baseRows=" + rows(baseEstimateRows)
					+ " adjustedRows=" + rows(adjustedEstimateRows)
					+ " qError=" + (interval == null ? "unknown" : interval.qError())
					+ " confidence=" + (interval == null ? "unknown" : interval.confidence())
					+ " goal=" + physicalGoal);
		}

		@Override
		public synchronized void ruleFired(int memoGroupId, String ruleId, RuleProof proof) {
			append("rule group=" + memoGroupId + " rule=" + ruleId + " proof={"
					+ (proof == null ? "" : proof.metricFragment()) + "}");
		}

		@Override
		public synchronized void alternativeConsidered(int memoGroupId, String ruleId, RuleKind kind,
				PhysicalProperties deliveredProperties, CostVector localCost, String metadata, QueryModelNode plan) {
			append("consider group=" + memoGroupId
					+ " rule=" + ruleId
					+ " kind=" + kind
					+ " delivered=" + deliveredProperties
					+ " localCost=" + localCost
					+ " metadata=" + safe(metadata)
					+ " plan=" + plan(plan));
		}

		@Override
		public synchronized void alternativeCosted(int memoGroupId, String ruleId,
				PhysicalProperties requiredProperties, PhysicalProperties deliveredProperties, CostVector cost,
				QueryModelNode plan) {
			append("costed group=" + memoGroupId
					+ " rule=" + ruleId
					+ " required=" + requiredProperties
					+ " delivered=" + deliveredProperties
					+ " cost=" + cost
					+ " plan=" + plan(plan));
		}

		@Override
		public synchronized void alternativeAccepted(int memoGroupId, String ruleId, CostVector cost,
				QueryModelNode plan) {
			append("accepted group=" + memoGroupId
					+ " rule=" + ruleId
					+ " cost=" + cost
					+ " plan=" + plan(plan));
		}

		@Override
		public synchronized void winnerChosen(WinnerKey key, Winner winner) {
			String line = "winner group=" + key.groupId()
					+ " required=" + key.requiredProperties()
					+ " cost=" + winner.cost()
					+ " delivered=" + winner.deliveredProperties()
					+ " approximate=" + winner.approximate();
			chosenWinnerByGroup.put(key.groupId(), line);
			append(line);
		}

		@Override
		public synchronized void alternativeRejected(int memoGroupId, String ruleId, String reason, CostVector cost) {
			alternativeDiscarded(memoGroupId, ruleId, reason, cost, null);
		}

		@Override
		public synchronized void alternativeDiscarded(int memoGroupId, String ruleId, String reason, CostVector cost,
				QueryModelNode plan) {
			append("discard group=" + memoGroupId
					+ " rule=" + ruleId
					+ " reason=" + reason
					+ " cost=" + cost
					+ " plan=" + plan(plan));
		}

		@Override
		public synchronized void executionActual(QueryModelNode node, long rows, long work) {
			append("actual node=" + (node == null ? "<null>" : node.getSignature()) + " rows=" + rows + " work="
					+ work);
		}

		public synchronized List<String> trace() {
			return List.copyOf(trace);
		}

		public Map<Integer, String> chosenWinnerByGroup() {
			return Map.copyOf(chosenWinnerByGroup);
		}

		private void append(String line) {
			if (trace.size() >= limit) {
				trace.remove(0);
			}
			trace.add(line);
			logger.debug("Cascades {}", line);
		}

		private String rows(double rows) {
			if (!Double.isFinite(rows)) {
				return Double.toString(rows);
			}
			return String.format(Locale.ROOT, "%.3f", rows);
		}

		private String plan(QueryModelNode node) {
			if (node == null) {
				return "<null>";
			}
			String text = node.toString()
					.replace('\n', ' ')
					.replace('\r', ' ')
					.replaceAll("\\s+", " ")
					.trim();
			if (text.isEmpty()) {
				text = node.getSignature();
			}
			if (text.length() <= PLAN_TEXT_LIMIT) {
				return text;
			}
			return text.substring(0, PLAN_TEXT_LIMIT) + "...";
		}

		private String safe(String text) {
			return text == null ? "" : text;
		}
	}
}
